values.content:
=You are an expert SEO content writer. Write a comprehensive, engaging, SEO-optimized article based on this brief:

Title: {{$node['Fetch Brief'].json[0].title}}
Target Keyword: {{$node['Fetch Brief'].json[0].target_keyword}}
Secondary Keywords: {{$node['Fetch Brief'].json[0].secondary_keywords}}
Outline: {{$node['Fetch Brief'].json[0].outline}}
Brief: {{$node['Fetch Brief'].json[0].brief_text}}
Client Domain: {{$node['Fetch Brief'].json[0].domain}}

Requirements:
- 1500-2500 words
- Include target keyword in H1, first paragraph, and naturally throughout
- Use secondary keywords in H2 headers
- Include meta title (under 60 chars) and meta description (under 160 chars)
- Write engaging, human-sounding content
- Include a compelling introduction and conclusion
- Use short paragraphs and bullet points for readability

Respond in JSON format:
{
  "title": "...",
  "meta_title": "...",
  "meta_description": "...",
  "slug": "...",
  "body": "...markdown content...",
  "word_count": number,
  "seo_score": number (0-100)
}

parameters.jsCode:
const brief = $('Fetch Brief').item.json[0];
const response = $input.item.json;

let article;
try {
  article = typeof response.text === 'string' ? JSON.parse(response.text) : response;
} catch (e) {
  article = {
    title: brief.title,
    meta_title: brief.title.substring(0, 60),
    meta_description: (brief.brief_text || '').substring(0, 160),
    slug: brief.title.toLowerCase().replace(/[^a-z0-9]+/g, '-'),
    body: response.text || '',
    word_count: (response.text || '').split(/\s+/).length,
    seo_score: 65
  };
}

return [{
  json: {
    ...article,
    brief_id: brief.id,
    client_id: brief.client_id
  }
}];
